package edu.ncsu.csc326.lexer;

import java.util.ArrayList;
import java.util.List;

/**
 * A Token is a single unit of lexical analysis. It is a pair of a token type and a
 * string value.
 * 
 * @author James McCaffrey
 *
 */
public class Token {
    private TokenType type;
    private String value;
    private int line;
    private int column;

    /**
     * Creates a new Token with the given type and value.
     * 
     * @param type
     *            the type of the token
     * @param value
     *            the value of the token
     */
    public Token(TokenType type, String value) {
        this.type = type;
        this.value = value;
    }

